	planName := ""
	if inst.PlanFile != "" {
		planName = planstate.DisplayName(inst.PlanFile)
	}
	return opencodesession.TitleOpts{
		PlanName:      planName,
		AgentType:     inst.AgentType,
		WaveNumber:    inst.WaveNumber,
